import{_ as a,o as e,c as d,a2 as i}from"./chunks/framework.CWNAqwu3.js";const b=JSON.parse('{"title":"环境变量参考","description":"","frontmatter":{"title":"环境变量参考"},"headers":[],"relativePath":"guide/environment-variables.md","filePath":"guide/environment-variables.md"}'),r={name:"guide/environment-variables.md"};function o(s,t,n,l,h,c){return e(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="环境变量参考" tabindex="-1">环境变量参考 <a class="header-anchor" href="#环境变量参考" aria-label="Permalink to &quot;环境变量参考&quot;">​</a></h1><h2 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>DATABASE_URL</td><td>sqlite3:db/development.sqlite3</td><td>数据库连接字符串</td></tr></tbody></table><h2 id="认证" tabindex="-1">认证 <a class="header-anchor" href="#认证" aria-label="Permalink to &quot;认证&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>JWT_SECRET</td><td>(从 credentials 读取)</td><td>JWT 签名密钥</td></tr><tr><td>SECRET_KEY_BASE</td><td>(Rails 生成)</td><td>Session Cookie 签名密钥</td></tr></tbody></table><h2 id="cors" tabindex="-1">CORS <a class="header-anchor" href="#cors" aria-label="Permalink to &quot;CORS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>ALLOWED_ORIGINS</td><td>(空)</td><td>CORS 允许的源，逗号分隔</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">生产环境必须设置</p><p>生产环境必须设置 <code>ALLOWED_ORIGINS</code> 环境变量，否则 CORS 请求会被拒绝。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ALLOWED_ORIGINS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">https://your-domain.com</span></span></code></pre></div><p>开发环境可创建 <code>.env.development</code> 文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ALLOWED_ORIGINS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:3100,http://localhost:5173,http://your-dev-domain.test</span></span></code></pre></div></div><h2 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-label="Permalink to &quot;部署&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>RAILS_ENV</td><td>development</td><td>Rails 环境</td></tr><tr><td>RAILS_MAX_THREADS</td><td>5</td><td>最大线程数</td></tr><tr><td>PORT</td><td>3000</td><td>服务端口</td></tr><tr><td>ALLOWED_HOSTS</td><td>localhost</td><td>允许的主机名</td></tr><tr><td>RAILS_LOG_LEVEL</td><td>info</td><td>日志级别</td></tr></tbody></table><h2 id="文件存储-minio-s3" tabindex="-1">文件存储（MinIO/S3） <a class="header-anchor" href="#文件存储-minio-s3" aria-label="Permalink to &quot;文件存储（MinIO/S3）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变量</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td>MINIO_ENDPOINT</td><td><code>http://localhost:9000</code></td><td>MinIO API 地址</td></tr><tr><td>MINIO_ACCESS_KEY</td><td>-</td><td>Access Key</td></tr><tr><td>MINIO_SECRET_KEY</td><td>-</td><td>Secret Key</td></tr><tr><td>MINIO_REGION</td><td>us-east-1</td><td>区域</td></tr><tr><td>MINIO_BUCKET</td><td>zen-platform</td><td>存储桶名称</td></tr></tbody></table><h2 id="安全配置说明" tabindex="-1">安全配置说明 <a class="header-anchor" href="#安全配置说明" aria-label="Permalink to &quot;安全配置说明&quot;">​</a></h2><h3 id="csp-content-security-policy" tabindex="-1">CSP（Content Security Policy） <a class="header-anchor" href="#csp-content-security-policy" aria-label="Permalink to &quot;CSP（Content Security Policy）&quot;">​</a></h3><ul><li><strong>生产环境</strong>：使用 <code>nonce</code> 策略，禁止 <code>unsafe-inline</code></li><li><strong>开发环境</strong>：允许 <code>unsafe_inline</code>（Vite HMR 需要）</li></ul><h3 id="inertia-history-encryption" tabindex="-1">Inertia History Encryption <a class="header-anchor" href="#inertia-history-encryption" aria-label="Permalink to &quot;Inertia History Encryption&quot;">​</a></h3><ul><li><strong>生产环境</strong>：启用（需要 SSL）</li><li><strong>开发环境</strong>：禁用（HTTP 环境不支持）</li></ul><h3 id="cors-1" tabindex="-1">CORS <a class="header-anchor" href="#cors-1" aria-label="Permalink to &quot;CORS&quot;">​</a></h3><ul><li>生产环境通过 <code>ALLOWED_ORIGINS</code> 环境变量控制</li><li>开发环境使用 <code>.env.development</code> 文件配置</li><li>未设置时默认拒绝所有跨域请求</li></ul>',19)])])}const u=a(r,[["render",o]]);export{b as __pageData,u as default};
